mapper.select:
SELECT 1
FROM member_tbl1
WHERE member_id = #{memberId}
AND member_email = #{memberEmail}

mapper.update:
update member_tbl1
set member_pw =#{memberPw}
where member_id = #{memberId}

update member_tbl1 set member_name = nvl(#{memberName}, member_name),
	member_nickname=#{memberNickname},
	member_email=#{memberEmail}
where member_id=#{memberId}

mapper.select:
SELECT TOTAL_POINT
FROM MEMBER_POINT_TBL
WHERE MEMBER_ID = #{memberId}

mapper.update:
UPDATE MEMBER_POINT_TBL
SET TOTAL_POINT = TOTAL_POINT - #{point}
WHERE MEMBER_ID = #{memberId}

mapper.select:
select lock_until as "lockUntil", lock_reason as "lockReason", member_status as "memberStatus"
from member_tbl1 
where member_id = #{memberId}
